def average(nums):
    """Return the arithmetic mean of nums as a float."""
    return sum(nums) / len(nums)

def dedupe(items):
    """Remove duplicate items while preserving original order."""
    seen = set()
    result = []
    for item in items:
        if item not in seen:
            seen.add(item)
            result.append(item)
    return result

def count_vowels(s):
    """Return the number of vowels in s. Case-insensitive."""
    return sum(1 for c in s.lower() if c in "aeiou")
